const body = items[0].json.body;
const text = body.text || '';
const channel = body.channel_id || '';
const requestedBy = body.user_name || 'unknown';

const username = text.trim().replace(/[^a-zA-Z0-9._-]/g, '');

if (!username || username.length === 0) {
  return [{ json: { error: true, message: 'Invalid username provided. Only alphanumeric characters, dots, hyphens, and underscores are allowed.' } }];
}

if (username.length > 64) {
  return [{ json: { error: true, message: 'Username too long. Maximum 64 characters allowed.' } }];
}

return [{ json: { user_to_search: username, response_channel: channel, requested_by: requestedBy } }];

