const item = items[0].json;

if (item.error || !item.stdout || item.stdout.trim() === '') {
  return [{ json: { status: 'error', message: item.stderr || 'No output from AD script. The script may have timed out or encountered an error.' } }];
}

let parsedData = null;

try {
  parsedData = JSON.parse(item.stdout);
} catch (parseError) {
  const jsonMatch = item.stdout.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    try {
      parsedData = JSON.parse(jsonMatch[0]);
    } catch (e) {
      return [{ json: { status: 'error', message: 'Failed to parse PowerShell output. Raw output: ' + item.stdout.substring(0, 200) } }];
    }
  } else {
    return [{ json: { status: 'error', message: 'Unexpected response format from AD server.' } }];
  }
}

if (!parsedData || !parsedData.status) {
  return [{ json: { status: 'error', message: 'AD response missing required status field.' } }];
}

return [{ json: parsedData }];

